import React, { useState } from "react";
import { analyzeImage } from "./api";
import "./App.css"; // Ensure Tailwind is imported in App.css or index.css

function App() {
  const [file, setFile] = useState(null);
  const [report, setReport] = useState("");
  const [loading, setLoading] = useState(false);

  const handleFileChange = (e) => {
    setFile(e.target.files[0]);
  };

  const handleUpload = async () => {
    if (!file) return;
    setLoading(true);
    try {
      const response = await analyzeImage(file);
      setReport(response.data.AI_Analysis);
    } catch (error) {
      console.error("Error analyzing image:", error);
      setReport("Error analyzing image");
    }
    setLoading(false);
  };

  return (
    <div className="min-h-screen flex flex-col items-center bg-gray-100">
      {/* Header / Hero Section */}
      <header className="w-full bg-gradient-to-r from-blue-600 to-blue-700 py-8 text-white text-center shadow-md">
        <h1 className="text-4xl font-extrabold">Radiology & Oncology AI</h1>
        <p className="mt-2 text-lg font-medium">
          Harness AI to assist in medical imaging analysis
        </p>
      </header>

      {/* Main Content Container */}
      <main className="flex flex-col items-center w-full max-w-4xl mx-auto mt-8 px-4">
        {/* Card for Upload & Analysis */}
        <div className="bg-white rounded-xl shadow-lg p-6 w-full">
          <h2 className="text-2xl font-semibold text-gray-800 text-center mb-4">
            Upload Medical Image
          </h2>

          <div className="flex flex-col items-center">
            {/* File Input */}
            <label className="block w-full max-w-md mb-4">
              <span className="sr-only">Choose Medical Image</span>
              <input
                type="file"
                accept="image/*"
                className="block w-full text-sm text-gray-700
                  file:mr-4 file:py-2 file:px-4
                  file:rounded-md file:border-0
                  file:text-sm file:font-semibold
                  file:bg-blue-600 file:text-white
                  hover:file:bg-blue-700 cursor-pointer"
                onChange={handleFileChange}
              />
            </label>

            {/* Analyze Button */}
            <button
              onClick={handleUpload}
              disabled={loading}
              className={`mt-2 px-6 py-3 rounded-md text-white font-semibold 
                          transition-all shadow-md 
                          ${loading ? "bg-gray-400" : "bg-blue-600 hover:bg-blue-700"}`}
            >
              {loading ? "Analyzing..." : "Analyze Image"}
            </button>
          </div>
        </div>

        {/* Results Card */}
        {report && (
          <div className="bg-white rounded-xl shadow-lg p-6 w-full mt-6">
            <h3 className="text-xl font-bold text-gray-800 border-b pb-2">AI Findings</h3>
            <p className="mt-4 text-gray-700 whitespace-pre-line">{report}</p>
          </div>
        )}

        {/* Disclaimer */}
        <div className="mt-6 bg-yellow-100 border-l-4 border-yellow-400 text-yellow-700 p-4 w-full rounded-md">
          <p className="text-sm">
            <strong>Disclaimer:</strong> This AI tool is intended to assist with medical imaging 
            analysis. It does <em>not</em> replace a certified medical professional. Always consult 
            a qualified medical practitioner for final interpretation.
          </p>
        </div>
      </main>

      {/* Footer */}
      <footer className="w-full text-center text-gray-500 text-sm mt-8 py-4">
        © 2025 Radiology AI. All rights reserved.
      </footer>
    </div>
  );
}

export default App;
